    "budget_signal": "Confirmed $25-50k range for Q3 spend.",
    "evidence_links": [
      "https://drive.acme.com/calls/2026-05-21-discovery.md",
      "https://stripe.com/dashboard/payments?period=last30"
    ]
  },
  "options": [
    {"name": "light", "scope": "Stripe retry tuning + checkout-path latency budget", "price": 6500, "duration_weeks": 2},
    {"name": "standard", "scope": "Light + p95 latency rebuild + new retry policy roll-out", "price": 18000, "duration_weeks": 6},
    {"name": "outcome-based", "scope": "Standard with success fee tied to retry-rate reduction below 6%", "price": 12000, "duration_weeks": 6}
  ],
  "actions": [
    {"owner": "Anna Schmidt", "due_date": "2026-05-26", "action": "Send proposal PDF to procurement contact"},
    {"owner": "Acme PM", "due_date": "2026-06-02", "action": "Confirm chosen option in writing"}
